---@class StructMail
local StructMail = LxClass("StructMail", nil)

StructMail.NORMAL = 1
StructMail.SPECIAL = 2

function StructMail:StructMail()
	self._refId = 1
	self._mailId = 0
	self._tile = ""
	self._contentSummary=""
	self._content = ""
	--self._sendId = 0
	self._sendImg = ""
	self._sendName = ""
	self._receiveTime = 0
	self._expiredTime = 0
	self._mailType = 1
	self._read = false
	self._fetch = false
	self._attachments = {}
end

function StructMail:CreateByPb(pb)
	self._mailId = pb.mailId
	self._refId = pb.refId
	self._tile = pb.tile
	self._contentSummary=pb.contentSummary
	self._content = pb.content
	--self._sendId = pb.sendId
	self._sendImg = pb.sendImg
	self._sendName = pb.sendName
	self._receiveTime = pb.receiveTime
	self._expiredTime = pb.expiredTime
	self._mailType = pb.mailType
	self._read = pb.read == 1
	self._fetch = pb.fetch == 1
	self._signature  = pb.signature

	local attachments = pb.attachments
	if attachments then
		for k,v in ipairs(attachments) do
			self._attachments[k] = {
				itemId = v.itemId,
				count = v.count,
				type = v.type,
				--effect= v.effect
			}
		end
	end
end

function StructMail:IsRead()
	return self._read
end

return StructMail